if (cards.length !== 133) {
  throw new Error(`Expected 133 cards, found ${cards.length}`);
}

function readTsv(path) {
  const lines = readFileSync(path, 'utf8').trimEnd().split('\n');
  return { header: lines[0], body: lines.slice(1) };
}

function wikiUrl(page) {
  return `https://en.wikipedia.org/wiki/${page}`;
}

function commonsSearch(title) {
  return `https://commons.wikimedia.org/wiki/Special:MediaSearch?type=image&search=${encodeURIComponent(title)}`;
}

const { header, body } = readTsv(TSV_PATH);
const existingIds = new Set(body.map((line) => line.split('\t')[1]));
const nextBody = [...body];

for (const card of cards) {
  if (card[8].length !== 2) {
    throw new Error(`${card[0]} must define exactly two combatant display sides`);
  }
  if (existingIds.has(card[0])) continue;
  nextBody.push([
    nextBody.length + 1,
    card[0],
    card[1],
    card[2],
    card[3],
    card[4],
    'research-pending',
    'needs-row-level-source',
    'priority-omission',
    wikiUrl(card[5]),
    commonsSearch(card[1]),
    card[6],
  ].join('\t'));
}

writeFileSync(TSV_PATH, `${header}\n${nextBody.join('\n')}\n`);

const details = JSON.parse(readFileSync(DETAILS_PATH, 'utf8'));
for (const card of cards) {
  details[card[0]] = {
    year: card[7],
    combatants: card[8],
    outcome: card[9],
    war: card[10],
    location: card[11],
    series: {
      key: card[12][0],
      label: card[12][1],
      order: card[12][2],
    },
    gloss: card[13],
  };
  if (card[14]) {
    details[card[0]].casualties = card[14];
  }
}

writeFileSync(DETAILS_PATH, `${JSON.stringify(details, null, 2)}\n`);

console.log(`Rows in ${TSV_PATH}: ${nextBody.length}`);
console.log(`Details in ${DETAILS_PATH}: ${Object.keys(details).length}`);
